"use strict";(globalThis.webpackChunksuperpai_docs=globalThis.webpackChunksuperpai_docs||[]).push([[5668],{774(e){e.exports=JSON.parse('{"version":{"pluginId":"orchestrate","version":"current","label":"Next","banner":null,"badge":false,"noIndex":false,"className":"docs-version-current","isLast":true,"docsSidebars":{"orchestrateSidebar":[{"type":"link","href":"/orchestrate/intro","label":"Platform Overview","docId":"intro","unlisted":false},{"type":"link","href":"/orchestrate/getting-started","label":"Getting Started","docId":"getting-started","unlisted":false},{"type":"link","href":"/orchestrate/architecture","label":"Architecture","docId":"architecture","unlisted":false},{"type":"category","label":"Administrator Guide","collapsed":false,"items":[{"type":"link","href":"/orchestrate/admin-guide","label":"Admin Guide","docId":"admin-guide","unlisted":false},{"type":"link","href":"/orchestrate/settings","label":"Settings","docId":"settings","unlisted":false},{"type":"link","href":"/orchestrate/channels","label":"Channels","docId":"channels","unlisted":false},{"type":"link","href":"/orchestrate/workflows","label":"Workflows","docId":"workflows","unlisted":false}],"collapsible":true},{"type":"category","label":"Daily Operations","collapsed":false,"items":[{"type":"link","href":"/orchestrate/dashboard","label":"Dashboard","docId":"dashboard","unlisted":false},{"type":"link","href":"/orchestrate/communications","label":"Communications","docId":"communications","unlisted":false},{"type":"link","href":"/orchestrate/booking-pipeline","label":"Booking Pipeline","docId":"booking-pipeline","unlisted":false},{"type":"link","href":"/orchestrate/operations","label":"Operations","docId":"operations","unlisted":false}],"collapsible":true},{"type":"category","label":"Data & Finance","collapsed":false,"items":[{"type":"link","href":"/orchestrate/master-data","label":"Master Data","docId":"master-data","unlisted":false},{"type":"link","href":"/orchestrate/accounting-crm","label":"Accounting & CRM","docId":"accounting-crm","unlisted":false}],"collapsible":true},{"type":"link","href":"/orchestrate/anna-ai","label":"Anna AI","docId":"anna-ai","unlisted":false},{"type":"link","href":"/orchestrate/storefronts","label":"Storefronts","docId":"storefronts","unlisted":false},{"type":"link","href":"/orchestrate/admin-portal","label":"Admin Portal","docId":"admin-portal","unlisted":false},{"type":"link","href":"/orchestrate/glossary","label":"Glossary","docId":"glossary","unlisted":false}]},"docs":{"accounting-crm":{"id":"accounting-crm","title":"Accounting & CRM","description":"Anshin Orchestrate includes built-in financial management and customer relationship tools powered by the ERPNext framework. Most financial documents are auto-generated from your booking activity \u2014 your primary job is to verify accuracy, process exceptions, and monitor the financial health of your business.","sidebar":"orchestrateSidebar"},"admin-guide":{"id":"admin-guide","title":"Administrator Guide","description":"This guide covers everything a SaaS Client Administrator needs to configure and maintain their Anshin Orchestrate organization. Administrators have full access to all settings and are responsible for setting up the system for their team.","sidebar":"orchestrateSidebar"},"admin-portal":{"id":"admin-portal","title":"Admin Portal","description":"The Admin Portal is a separate application used exclusively by Anshin Health Solutions staff to manage all tenants, platform health, billing, AI infrastructure, and data operations. Tour operator clients do not have access to this portal.","sidebar":"orchestrateSidebar"},"anna-ai":{"id":"anna-ai","title":"Anna AI","description":"Anna is the AI assistant built directly into Anshin Orchestrate. She handles email classification, package matching, chat Q&A, voice interaction, workflow decisions, and knowledge retrieval \u2014 all running on self-hosted infrastructure so your data never leaves your servers.","sidebar":"orchestrateSidebar"},"architecture":{"id":"architecture","title":"Anshin Orchestrate Architecture","description":"Anshin Orchestrate is a modern, multi-tenant SaaS platform built on a purpose-designed stack for tour operations management. This page describes the technology foundation, component design, and how the pieces work together.","sidebar":"orchestrateSidebar"},"booking-pipeline":{"id":"booking-pipeline","title":"Booking Pipeline","description":"The booking pipeline is the operational heart of Anshin Orchestrate. Every tour booking \u2014 whether it arrives via email, OTA platform, WhatsApp, or direct website \u2014 flows through a defined series of stages from initial inquiry to completed tour and post-tour follow-up.","sidebar":"orchestrateSidebar"},"channels":{"id":"channels","title":"Channels & OTA Integrations","description":"The Channels section manages all of Orchestrate\'s connections to Online Travel Agencies (OTAs) and distribution platforms. It is where you configure integrations, monitor incoming bookings, sync availability, and track connection health.","sidebar":"orchestrateSidebar"},"communications":{"id":"communications","title":"Communications","description":"The Communications section is Orchestrate\'s unified inbox \u2014 all customer interactions across email, WhatsApp, and internal contacts flow through a single, integrated interface. Agents never need to switch between separate email clients, messaging apps, or contact databases.","sidebar":"orchestrateSidebar"},"dashboard":{"id":"dashboard","title":"Dashboard","description":"The Dashboard is your operational command center \u2014 a real-time overview of your tour business. It loads immediately after login and provides at-a-glance visibility into what\'s happening today, what needs attention, and how your business is performing.","sidebar":"orchestrateSidebar"},"getting-started":{"id":"getting-started","title":"Getting Started with Anshin Orchestrate","description":"This guide walks you through signing up for Anshin Orchestrate, choosing your plan, completing the onboarding wizard, and taking your first steps as an administrator.","sidebar":"orchestrateSidebar"},"glossary":{"id":"glossary","title":"Glossary","description":"A reference for all terms used throughout the Anshin Orchestrate platform and documentation.","sidebar":"orchestrateSidebar"},"intro":{"id":"intro","title":"What is Anshin Orchestrate?","description":"Anshin Orchestrate is a multi-tenant tour operations management platform built for tour operators, activity providers, and travel companies. It centralizes every aspect of running a tour business \u2014 from the first customer inquiry through booking confirmation, day-of-departure coordination, provider settlement, and post-tour follow-up \u2014 into a single, AI-powered workspace.","sidebar":"orchestrateSidebar"},"master-data":{"id":"master-data","title":"Master Data","description":"Master Data is the foundational reference layer of Anshin Orchestrate \u2014 the business objects that everything else depends on. Products, providers, customers, locations, seasons, pricing, and policies are all configured here. Getting master data right is the single most important setup task for any new organization.","sidebar":"orchestrateSidebar"},"operations":{"id":"operations","title":"Operations","description":"The Operations section provides all the tools needed for day-to-day tour execution \u2014 managing departures, coordinating providers, monitoring AI decisions, and ensuring every guest has a seamless experience.","sidebar":"orchestrateSidebar"},"settings":{"id":"settings","title":"Settings Reference","description":"The Settings section gives administrators control over all aspects of their Orchestrate organization \u2014 from general preferences to AI configuration, email connections, workflow automation, channel integrations, and pricing.","sidebar":"orchestrateSidebar"},"storefronts":{"id":"storefronts","title":"Public-Facing Storefronts","description":"Anshin Orchestrate powers customer-facing booking experiences through two integration patterns. Both allow your website visitors to browse your tour catalog and submit booking requests that flow directly into your Orchestrate pipeline.","sidebar":"orchestrateSidebar"},"workflows":{"id":"workflows","title":"Workflow Automation","description":"Anshin Orchestrate includes a built-in workflow automation engine powered by self-hosted N8N. Workflows automate repetitive tasks \u2014 sending manifests, delivering itineraries, processing follow-ups, routing bookings, and making AI-assisted decisions \u2014 so your team spends time on guests, not administration.","sidebar":"orchestrateSidebar"}}}}')}}]);